/**
 * Pre-build script: reads ffmpeg.exe and generates ffmpeg-bundle.js
 * as a CommonJS module exporting the binary as a base64-encoded Buffer.
 *
 * This avoids relying on pkg's `assets` config (which is unreliable in v5.8.1)
 * by bundling ffmpeg.exe as plain JavaScript that pkg handles naturally.
 */
'use strict';
const fs = require('fs');
const path = require('path');

const ffmpegSrc = path.join(__dirname, '..', 'nssm', 'ffmpeg.exe');
const outFile = path.join(__dirname, '..', 'ffmpeg-bundle.js');

if (!fs.existsSync(ffmpegSrc)) {
  console.error('[bundle-ffmpeg] ERROR: ffmpeg.exe not found at', ffmpegSrc);
  process.exit(1);
}

const data = fs.readFileSync(ffmpegSrc);
const base64 = data.toString('base64');

const output = `// Auto-generated by scripts/bundle-ffmpeg.js — do not edit manually
'use strict';
module.exports = Buffer.from('${base64}', 'base64');
`;

fs.writeFileSync(outFile, output);
console.log('[bundle-ffmpeg] \u2713 ffmpeg-bundle.js generated (' + (Buffer.byteLength(output) / 1024 / 1024).toFixed(1) + ' MB)');
